183	/// State machine for reading a numeric literal byte-by-byte from a file.
184	/// C: `typedef struct { FILE *f; int c; int n; char buff[L_MAXLENNUM+1]; } RN`.
185	struct ReadNumState {
186	    /// Current look-ahead byte, or `EOF_SENTINEL`.
187	    current: i32,
188	    /// Number of bytes accumulated in `buf`.
189	    count: usize,
190	    /// Accumulated characters of the numeral (NUL-terminated on finalise).
191	    buf: [u8; L_MAX_LEN_NUM + 1],
192	}
193	
194	impl ReadNumState {
195	    fn new(first_byte: i32) -> Self {
196	        ReadNumState {
197	            current: first_byte,
198	            count: 0,
199	            buf: [0u8; L_MAX_LEN_NUM + 1],
200	        }
201	    }
202	
203	    /// Save current char to `buf` and read the next byte from `file`.
204	    /// Returns `false` if the buffer is full (numeral too long). C: `nextc`.
205	    fn advance(&mut self, file: &mut dyn LuaFileHandle) -> bool {
206	        // C: if (rn->n >= L_MAXLENNUM) { rn->buff[0] = '\0'; return 0; }
207	        if self.count >= L_MAX_LEN_NUM {
208	            self.buf[0] = 0;
209	            return false;
210	        }
211	        self.buf[self.count] = self.current as u8;
212	        self.count += 1;
213	        self.current = file.read_byte();
214	        true
215	    }
216	
217	    /// Accept current char if it equals either byte in `set`. C: `test2`.
218	    fn try2(&mut self, file: &mut dyn LuaFileHandle, set: [u8; 2]) -> bool {
219	        // C: if (rn->c == set[0] || rn->c == set[1]) return nextc(rn);
220	        if self.current == set[0] as i32 || self.current == set[1] as i32 {
221	            self.advance(file)
222	        } else {
223	            false
224	        }
225	    }
226	
227	    /// Consume a run of (hex)digits; return the count. C: `readdigits`.
228	    fn read_digits(&mut self, file: &mut dyn LuaFileHandle, hex: bool) -> usize {
229	        // C: while ((hex ? isxdigit(rn->c) : isdigit(rn->c)) && nextc(rn)) count++;
230	        let mut count = 0usize;
231	        loop {
232	            let is_digit = if hex {
233	                (self.current as u8).is_ascii_hexdigit()
234	            } else {
235	                (self.current as u8).is_ascii_digit()
236	            };
237	            if !is_digit || self.current == EOF_SENTINEL {
238	                break;
239	            }
240	            if !self.advance(file) {
241	                break;
242	            }
243	            count += 1;
244	        }
245	        count
246	    }
247	
248	    /// Return the accumulated bytes (without the NUL terminator).
249	    fn as_bytes(&self) -> &[u8] {
250	        &self.buf[..self.count]
251	    }
252	}
