289	// ── Helpers ──────────────────────────────────────────────────────────────────
290	
291	/// Validate an `fopen` mode string: must match `[rwa]\+?b*`. C: `l_checkmode`.
292	///
293	/// C: `return (*mode != '\0' && strchr("rwa", *(mode++)) != NULL &&
294	///           (*mode != '+' || ...) && strspn(mode, "b") == strlen(mode));`
295	fn check_mode(mode: &[u8]) -> bool {
296	    if mode.is_empty() {
297	        return false;
298	    }
299	    let mut idx = 0usize;
300	    if !matches!(mode[idx], b'r' | b'w' | b'a') {
301	        return false;
302	    }
303	    idx += 1;
304	    if idx < mode.len() && mode[idx] == b'+' {
305	        idx += 1;
306	    }
307	    mode[idx..].iter().all(|&b| b == b'b')
308	}
309	
310	/// Validate a `popen` mode string: only `"r"` or `"w"`. C: `l_checkmodep`.
311	fn check_mode_popen(mode: &[u8]) -> bool {
312	    matches!(mode, b"r" | b"w")
313	}
314	
315	/// Push success (`true`) or failure (`false`, msg, errno) per `luaL_fileresult`.
316	///
317	/// C: `if (stat) { lua_pushboolean(L,1); return 1; }
318	///     else { luaL_pushfail; pushstring(msg); pushinteger(errno); return 3; }`
319	fn file_result(
320	    state: &mut LuaState,
321	    success: bool,
322	    fname: Option<&[u8]>,
323	    os_err: io::Error,
324	) -> Result<usize, LuaError> {
325	    if success {
326	        // C: lua_pushboolean(L, 1); return 1;
327	        state.push(LuaValue::Bool(true));
328	        return Ok(1);
329	    }
330	    // C: luaL_pushfail(L)  — Lua 5.4 pushfail = push false
331	    state.push(LuaValue::Bool(false));
332	    // C: msg = strerror(errno); if (fname) lua_pushfstring(L, "%s: %s", fname, msg);
333	    let msg = os_err.to_string();
334	    match fname {
335	        Some(name) => {
336	            let mut s = Vec::with_capacity(name.len() + 2 + msg.len());
337	            s.extend_from_slice(name);
338	            s.extend_from_slice(b": ");
339	            s.extend_from_slice(msg.as_bytes());
340	            state.push_string(&s);
341	        }
342	        None => {
343	            state.push_string(msg.as_bytes());
344	        }
345	    }
346	    // C: lua_pushinteger(L, en)
347	    let errno_code = os_err.raw_os_error().unwrap_or(0) as i64;
348	    state.push(LuaValue::Int(errno_code));
349	    Ok(3)
350	}
351	
352	/// Push popen/system exit-status results per `luaL_execresult`.
353	///
354	/// C: `if (stat == 0) { lua_pushboolean(L,1); return 1; }
355	///     else { luaL_pushfail; pushlstring("exit"|"signal"); pushinteger(stat); return 3; }`
356	///
357	/// TODO(port): POSIX `WIFEXITED`/`WTERMSIG` macros not available on all platforms;
358	/// this stub always treats non-zero stat as an exit code.
359	fn exec_result(state: &mut LuaState, stat: i32) -> Result<usize, LuaError> {
360	    if stat == 0 {
361	        state.push(LuaValue::Bool(true));
362	        Ok(1)
363	    } else {
364	        state.push(LuaValue::Bool(false));
365	        // TODO(port): distinguish exit vs signal via POSIX macros
366	        state.push_string(b"exit");
367	        state.push(LuaValue::Int(stat as i64));
368	        Ok(3)
369	    }
370	}
