372	/// Retrieve `LStream` from argument 1 via a userdata type-check.
373	/// C: `tolstream(L)` = `(LStream *)luaL_checkudata(L, 1, LUA_FILEHANDLE)`.
374	///
375	/// Returns an `Rc<RefCell<LStream>>` from the side-table registry. The C port
376	/// returns a raw `LStream *` pointing into the userdata payload; Rust uses a
377	/// side table because `LStream` contains heap pointers that cannot be safely
378	/// reinterpreted from a raw byte buffer in safe Rust.
379	fn get_lstream(state: &mut LuaState) -> Result<Rc<RefCell<LStream>>, LuaError> {
380	    let ud = state.check_arg_userdata(1, LUA_FILE_HANDLE)?;
381	    lookup_lstream(ud.identity()).ok_or_else(|| {
382	        LuaError::runtime(format_args!("invalid file handle"))
383	    })
384	}
385	
386	/// Validate that argument 1 is an open file handle; error if closed.
387	/// C: `tofile` (returns `FILE *` in C; here we return the wrapping `Rc<RefCell<LStream>>`).
388	fn tofile(state: &mut LuaState) -> Result<Rc<RefCell<LStream>>, LuaError> {
389	    let p_rc = get_lstream(state)?;
390	    {
391	        let p = p_rc.borrow();
392	        // C: if (isclosed(p)) luaL_error(L, "attempt to use a closed file");
393	        if p.is_closed() {
394	            return Err(LuaError::runtime(format_args!(
395	                "attempt to use a closed file"
396	            )));
397	        }
398	        // C: lua_assert(p->f);
399	        debug_assert!(p.file.is_some());
400	    }
401	    Ok(p_rc)
402	}
