404	// ── File creation helpers ────────────────────────────────────────────────────
405	
406	/// Allocate a "closed" file-handle userdata and push it; set its metatable.
407	/// Also registers an empty `LStream` in the side table keyed by the userdata
408	/// identity, and returns the `Rc<RefCell<LStream>>` so the caller may finish
409	/// initialising it (set `file`, set `close_fn`). C: `newprefile(L)`.
410	fn new_pre_file(state: &mut LuaState) -> Result<Rc<RefCell<LStream>>, LuaError> {
411	    // C: LStream *p = lua_newuserdatauv(L, sizeof(LStream), 0);
412	    let ud = state.new_userdata_typed(LUA_FILE_HANDLE, std::mem::size_of::<LStream>(), 0)?;
413	    // C: luaL_setmetatable(L, LUA_FILEHANDLE);
414	    state.set_metatable_by_name(LUA_FILE_HANDLE)?;
415	    // C: p->closef = NULL;  (LStream::close_fn = None marks the stream as closed)
416	    let cell = register_lstream(ud.identity(), LStream { file: None, close_fn: None });
417	    Ok(cell)
418	}
419	
420	/// Allocate a new regular-file handle with `io_fclose` as the close function.
421	/// C: `newfile(L)`.
422	fn new_file(state: &mut LuaState) -> Result<Rc<RefCell<LStream>>, LuaError> {
423	    // C: LStream *p = newprefile(L); p->f = NULL; p->closef = &io_fclose;
424	    let cell = new_pre_file(state)?;
425	    cell.borrow_mut().close_fn = Some(io_fclose);
426	    Ok(cell)
427	}
428	
429	/// Open `fname` and push its handle; raise a runtime error on failure.
430	/// C: `opencheck(L, fname, mode)`.
431	///
432	/// The file system is reached via `GlobalState::file_open_hook` (registered by
433	/// `lua-cli`) since `std::fs` is banned in `lua-stdlib` per PORTING.md §1.
434	fn opencheck(state: &mut LuaState, fname: &[u8], mode: &[u8]) -> Result<(), LuaError> {
435	    let hook = state.global().file_open_hook;
436	    let fh = match hook {
437	        Some(open_fn) => open_fn(fname, mode).map_err(|e| {
438	            LuaError::runtime(format_args!(
439	                "cannot open file '{}' ({})",
440	                fname.escape_ascii(),
441	                match &e {
442	                    LuaError::Runtime(LuaValue::Str(s)) => {
443	                        String::from_utf8_lossy(s.as_bytes()).into_owned()
444	                    }
445	                    other => format!("{:?}", other),
446	                }
447	            ))
448	        })?,
449	        None => {
450	            return Err(LuaError::runtime(format_args!(
451	                "cannot open file '{}' (no filesystem hook registered)",
452	                fname.escape_ascii()
453	            )));
454	        }
455	    };
456	    let cell = new_file(state)?;
457	    cell.borrow_mut().file = Some(fh);
458	    Ok(())
459	}
