461	// ── Close functions ──────────────────────────────────────────────────────────
462	
463	/// Close a regular file via `fclose`. C: `io_fclose`.
464	///
465	/// TODO(port): flush + drop `Box<dyn LuaFileOps>`, map io::Error to file_result.
466	fn io_fclose(state: &mut LuaState) -> Result<usize, LuaError> {
467	    // C: return luaL_fileresult(L, (fclose(p->f) == 0), NULL);
468	    let p_rc = get_lstream(state)?;
469	    // TODO(port): actually flush then drop p.file, capture any error
470	    let _closed = p_rc.borrow_mut().file.take();
471	    state.push(LuaValue::Bool(true));
472	    Ok(1)
473	}
474	
475	/// Close a popen process pipe. C: `io_pclose`.
476	///
477	/// TODO(port): std::process::Child — popen not yet implemented.
478	fn io_pclose(state: &mut LuaState) -> Result<usize, LuaError> {
479	    // C: return luaL_execresult(L, l_pclose(L, p->f));
480	    let p_rc = get_lstream(state)?;
481	    let _closed = p_rc.borrow_mut().file.take();
482	    // TODO(port): wait on the child process and forward its exit code
483	    exec_result(state, 0)
484	}
485	
486	/// Refuse to close a standard-stream handle. C: `io_noclose`.
487	fn io_noclose(state: &mut LuaState) -> Result<usize, LuaError> {
488	    // C: p->closef = &io_noclose;  /* keep file opened */
489	    // C: luaL_pushfail(L); lua_pushliteral(L, "cannot close standard file"); return 2;
490	    let p_rc = get_lstream(state)?;
491	    p_rc.borrow_mut().close_fn = Some(io_noclose); // reinstall to keep the handle alive
492	    state.push(LuaValue::Bool(false));
493	    state.push_string(b"cannot close standard file");
494	    Ok(2)
495	}
496	
497	/// Invoke the stream's close function and mark it closed. C: `aux_close`.
498	fn aux_close(state: &mut LuaState) -> Result<usize, LuaError> {
499	    // C: volatile lua_CFunction cf = p->closef; p->closef = NULL; return (*cf)(L);
500	    let p_rc = get_lstream(state)?;
501	    let cf = p_rc.borrow_mut().close_fn.take().ok_or_else(|| {
502	        LuaError::runtime(format_args!("attempt to close an already-closed file"))
503	    })?;
504	    cf(state)
505	}
