509	/// `io.type(x)` — return `"file"`, `"closed file"`, or `false`. C: `io_type`.
510	pub fn io_type(state: &mut LuaState) -> Result<usize, LuaError> {
511	    // C: luaL_checkany(L, 1);
512	    state.check_arg_any(1)?;
513	    // C: p = (LStream *)luaL_testudata(L, 1, LUA_FILEHANDLE);
514	    // C: if (p == NULL) luaL_pushfail(L);
515	    // C: else if (isclosed(p)) lua_pushliteral(L, "closed file");
516	    // C: else lua_pushliteral(L, "file");
517	    let maybe_userdata = state.test_arg_userdata(1, LUA_FILE_HANDLE);
518	    match maybe_userdata {
519	        None => {
520	            state.push(LuaValue::Bool(false));
521	        }
522	        Some(ud) => {
523	            let is_closed = match lookup_lstream(ud.identity()) {
524	                Some(rc) => rc.borrow().is_closed(),
525	                None => true, // unknown userdata with FILE* metatable: treat as closed
526	            };
527	            if is_closed {
528	                state.push_string(b"closed file");
529	            } else {
530	                state.push_string(b"file");
531	            }
532	        }
533	    }
534	    Ok(1)
535	}
