592	/// `io.open(filename [, mode])`. C: `io_open`.
593	///
594	/// The file system is reached via `GlobalState::file_open_hook` (registered by
595	/// `lua-cli`) since `std::fs` is banned in `lua-stdlib` per PORTING.md §1.
596	pub fn io_open(state: &mut LuaState) -> Result<usize, LuaError> {
597	    // C: const char *filename = luaL_checkstring(L, 1);
598	    // C: const char *mode = luaL_optstring(L, 2, "r");
599	    let filename: Vec<u8> = state.check_arg_string(1)?;
600	    let mode: Vec<u8> = state.opt_arg_string(2, b"r")?;
601	    // C: luaL_argcheck(L, l_checkmode(md), 2, "invalid mode");
602	    if !check_mode(&mode) {
603	        return Err(LuaError::arg_error(2, "invalid mode"));
604	    }
605	    let hook = state.global().file_open_hook;
606	    match hook {
607	        Some(open_fn) => match open_fn(&filename, &mode) {
608	            Ok(fh) => {
609	                let cell = new_file(state)?;
610	                cell.borrow_mut().file = Some(fh);
611	                // C: return 1; (the file handle userdata is on the stack)
612	                Ok(1)
613	            }
614	            Err(e) => {
615	                let os_err = io::Error::new(
616	                    io::ErrorKind::Other,
617	                    match &e {
618	                        LuaError::Runtime(LuaValue::Str(s)) => {
619	                            String::from_utf8_lossy(s.as_bytes()).into_owned()
620	                        }
621	                        other => format!("{:?}", other),
622	                    },
623	                );
624	                file_result(state, false, Some(&filename), os_err)
625	            }
626	        },
627	        None => {
628	            let os_err = io::Error::new(
629	                io::ErrorKind::Unsupported,
630	                "no filesystem hook registered",
631	            );
632	            file_result(state, false, Some(&filename), os_err)
633	        }
634	    }
635	}
