726	/// Read and push a Lua number from `file`. Return `true` on success.
727	/// C: `read_number(L, f)`.
728	fn read_number(
729	    state: &mut LuaState,
730	    file: &mut dyn LuaFileHandle,
731	) -> Result<bool, LuaError> {
732	    // C: do { rn.c = l_getc(rn.f); } while (isspace(rn.c)); /* skip spaces */
733	    let first = loop {
734	        let b = file.read_byte();
735	        if b == EOF_SENTINEL || !(b as u8).is_ascii_whitespace() {
736	            break b;
737	        }
738	    };
739	
740	    let mut rn = ReadNumState::new(first);
741	
742	    // C: test2(&rn, "-+")
743	    rn.try2(file, [b'-', b'+']);
744	
745	    // C: if (test2(&rn, "00")) { if (test2(&rn, "xX")) hex = 1; else count = 1; }
746	    let mut count: usize = 0;
747	    let hex = if rn.try2(file, [b'0', b'0']) {
748	        if rn.try2(file, [b'x', b'X']) {
749	            true
750	        } else {
751	            count = 1;
752	            false
753	        }
754	    } else {
755	        false
756	    };
757	
758	    // C: count += readdigits(&rn, hex);
759	    count += rn.read_digits(file, hex);
760	
761	    // C: decp[0] = lua_getlocaledecpoint(); decp[1] = '.';
762	    // TODO(port): locale decimal-point character; defaulting to '.'
763	    let dec_point = b'.';
764	    if rn.try2(file, [dec_point, b'.']) {
765	        count += rn.read_digits(file, hex);
766	    }
767	
768	    // C: if (count > 0 && test2(&rn, hex ? "pP" : "eE")) { ... exponent ... }
769	    if count > 0 {
770	        let exp_chars = if hex { [b'p', b'P'] } else { [b'e', b'E'] };
771	        if rn.try2(file, exp_chars) {
772	            rn.try2(file, [b'-', b'+']);
773	            rn.read_digits(file, false);
774	        }
775	    }
776	
777	    // C: ungetc(rn.c, rn.f);
778	    file.unread_byte(rn.current);
779	
780	    // C: if (lua_stringtonumber(L, rn.buff)) return 1; else { lua_pushnil(L); return 0; }
781	    // TODO(port): state.string_to_number(bytes) — parses bytes into LuaValue::Int or Float
782	    let bytes = rn.as_bytes();
783	    let pushed = state.string_to_number_push(&bytes)?;
784	    if pushed != 0 {
785	        Ok(true)
786	    } else {
787	        state.push(LuaValue::Nil);
788	        Ok(false)
789	    }
790	}
