792	/// Test for EOF: push `""` and return `true` if not at EOF. C: `test_eof`.
793	fn test_eof(
794	    state: &mut LuaState,
795	    file: &mut dyn LuaFileHandle,
796	) -> Result<bool, LuaError> {
797	    // C: int c = getc(f); ungetc(c, f); lua_pushliteral(L, ""); return (c != EOF);
798	    let c = file.read_byte();
799	    if c != EOF_SENTINEL {
800	        file.unread_byte(c);
801	    }
802	    state.push_string(b"");
803	    Ok(c != EOF_SENTINEL)
804	}
