806	/// Read one line from `file` and push it. If `chop`, strip the trailing `\n`.
807	/// Return `true` if anything was read. C: `read_line(L, f, chop)`.
808	///
809	/// PERF(port): C uses luaL_prepbuffer (large fixed stack buffer) to avoid
810	/// per-byte allocation; Rust's Vec grows here, which is slightly slower.
811	fn read_line(
812	    state: &mut LuaState,
813	    file: &mut dyn LuaFileHandle,
814	    chop: bool,
815	) -> Result<bool, LuaError> {
816	    let mut buf: Vec<u8> = Vec::new();
817	    let mut c: i32 = EOF_SENTINEL;
818	
819	    // C: do { char *buff = luaL_prepbuffer(&b); int i = 0;
820	    //          while (i < LUAL_BUFFERSIZE && (c = l_getc(f)) != EOF && c != '\n')
821	    //            buff[i++] = c;
822	    //          luaL_addsize(&b, i);
823	    //    } while (c != EOF && c != '\n');
824	    'outer: loop {
825	        for _ in 0..LUAL_BUFFER_SIZE {
826	            c = file.read_byte();
827	            if c == EOF_SENTINEL || c == b'\n' as i32 {
828	                break 'outer;
829	            }
830	            buf.push(c as u8);
831	        }
832	        // chunk full but no newline/EOF yet — continue reading
833	    }
834	
835	    // C: if (!chop && c == '\n') luaL_addchar(&b, c);
836	    if !chop && c == b'\n' as i32 {
837	        buf.push(b'\n');
838	    }
839	
840	    // C: return (c == '\n' || lua_rawlen(L, -1) > 0);
841	    let had_content = c == b'\n' as i32 || !buf.is_empty();
842	    state.push_string(&buf);
843	    Ok(had_content)
844	}
