846	/// Read the entire file into a single string and push it. C: `read_all(L, f)`.
847	///
848	/// PERF(port): C uses `fread` with a large buffer; Rust reads byte-by-byte via
849	/// `LuaFileOps::read_byte`. Phase B should add `read_chunk(&mut buf)` to the
850	/// trait for bulk reads.
851	fn read_all(state: &mut LuaState, file: &mut dyn LuaFileHandle) -> Result<(), LuaError> {
852	    // C: do { nr = fread(p, LUAL_BUFFERSIZE, f); luaL_addsize(&b, nr); } while (nr == LUAL_BUFFERSIZE);
853	    let mut buf: Vec<u8> = Vec::new();
854	    loop {
855	        let start = buf.len();
856	        let mut chunk_read = 0usize;
857	        for _ in 0..LUAL_BUFFER_SIZE {
858	            let b = file.read_byte();
859	            if b == EOF_SENTINEL {
860	                break;
861	            }
862	            buf.push(b as u8);
863	            chunk_read += 1;
864	        }
865	        if chunk_read < LUAL_BUFFER_SIZE {
866	            break;
867	        }
868	    }
869	    state.push_string(&buf);
870	    Ok(())
871	}
