873	/// Read exactly `n` bytes from `file` and push the result.
874	/// Return `true` if anything was read. C: `read_chars(L, f, n)`.
875	fn read_chars(
876	    state: &mut LuaState,
877	    file: &mut dyn LuaFileHandle,
878	    n: usize,
879	) -> Result<bool, LuaError> {
880	    // C: nr = fread(p, sizeof(char), n, f); luaL_addsize(&b, nr); return (nr > 0);
881	    let mut buf = Vec::with_capacity(n);
882	    for _ in 0..n {
883	        let b = file.read_byte();
884	        if b == EOF_SENTINEL {
885	            break;
886	        }
887	        buf.push(b as u8);
888	    }
889	    let nr = buf.len();
890	    state.push_string(&buf);
891	    Ok(nr > 0)
892	}
