894	/// Dispatch one or more read formats; push results. C: `g_read(L, f, first)`.
895	///
896	/// TODO(port): borrow split — `file` is `&mut dyn LuaFileOps` extracted from a
897	/// `LuaUserData` that lives inside `state`. Phase B must restructure so the file
898	/// is accessed through the stack index rather than a raw borrow.
899	fn g_read(
900	    state: &mut LuaState,
901	    file: &mut dyn LuaFileHandle,
902	    first: i32,
903	) -> Result<usize, LuaError> {
904	    // C: int nargs = lua_gettop(L) - 1;
905	    let nargs = state.top_idx().get() as i32 - 1;
906	    let mut n = first;
907	    let mut success = true;
908	
909	    // C: clearerr(f);
910	    file.clear_error();
911	
912	    if nargs == 0 {
913	        // C: success = read_line(L, f, 1); n = first + 1;
914	        success = read_line(state, file, true)?;
915	        n = first + 1;
916	    } else {
917	        // C: luaL_checkstack(L, nargs+LUA_MINSTACK, "too many arguments");
918	        state.ensure_stack((nargs as i32) + 20, "too many arguments")?;
919	        let mut remaining = nargs;
920	        while remaining > 0 && success {
921	            // C: if (lua_type(L, n) == LUA_TNUMBER)
922	            if state.type_at(n) == LuaType::Number {
923	                // C: size_t l = (size_t)luaL_checkinteger(L, n);
924	                let l = state.check_arg_integer(n)? as usize;
925	                success = if l == 0 {
926	                    test_eof(state, file)?
927	                } else {
928	                    read_chars(state, file, l)?
929	                };
930	            } else {
931	                // C: const char *p = luaL_checkstring(L, n);
932	                // C: if (*p == '*') p++;  /* skip optional '*' (compat) */
933	                let s: Vec<u8> = state.check_arg_string(n)?;
934	                let p: &[u8] = if s.first() == Some(&b'*') { &s[1..] } else { &s[..] };
935	                match p.first() {
936	                    // C: case 'n': success = read_number(L, f); break;
937	                    Some(&b'n') => {
938	                        success = read_number(state, file)?;
939	                    }
940	                    // C: case 'l': success = read_line(L, f, 1); break;
941	                    Some(&b'l') => {
942	                        success = read_line(state, file, true)?;
943	                    }
944	                    // C: case 'L': success = read_line(L, f, 0); break;
945	                    Some(&b'L') => {
946	                        success = read_line(state, file, false)?;
947	                    }
948	                    // C: case 'a': read_all(L, f); success = 1; break;
949	                    Some(&b'a') => {
950	                        read_all(state, file)?;
951	                        success = true;
952	                    }
953	                    _ => {
954	                        return Err(LuaError::arg_error(n, "invalid format"));
955	                    }
956	                }
957	            }
958	            n += 1;
959	            remaining -= 1;
960	        }
961	    }
962	
963	    // C: if (ferror(f)) return luaL_fileresult(L, 0, NULL);
964	    if file.has_error() {
965	        return file_result(
966	            state,
967	            false,
968	            None,
969	            io::Error::new(io::ErrorKind::Other, "file read error"),
970	        );
971	    }
972	
973	    // C: if (!success) { lua_pop(L, 1); luaL_pushfail(L); }
974	    if !success {
975	        state.pop_n(1);
976	        state.push(LuaValue::Bool(false));
977	    }
978	
979	    // C: return n - first;
980	    Ok((n - first) as usize)
981	}
