1004	/// Dispatch one or more write values. C: `g_write(L, f, arg)`.
1005	///
1006	/// TODO(port): borrow split — same issue as g_read.
1007	fn g_write(
1008	    state: &mut LuaState,
1009	    file: &mut dyn LuaFileHandle,
1010	    arg: i32,
1011	) -> Result<usize, LuaError> {
1012	    // C: int nargs = lua_gettop(L) - arg;
1013	    let nargs = state.top_idx().get() as i32 - arg;
1014	    let mut overall_ok = true;
1015	
1016	    for i in 0..nargs {
1017	        let idx = arg + i;
1018	        if state.type_at(idx) == LuaType::Number {
1019	            // C: lua_isinteger(L, arg) ? fprintf(LUA_INTEGER_FMT,...) : fprintf(LUA_NUMBER_FMT,...)
1020	            // C: LUA_INTEGER_FMT = "%lld" (i64)
1021	            // C: LUA_NUMBER_FMT  = "%.14g" (f64, 14 significant digits)
1022	            // PERF(port): byte-by-byte write; Phase B add bulk write_fmt to LuaFileOps.
1023	            // TODO(port): C's %.14g (significant digits) has no direct Rust equivalent.
1024	            let s = if state.is_integer(idx) {
1025	                let ival = state.to_integer(idx).unwrap_or(0);
1026	                // C: LUA_INTEGER_FMT = "%lld"
1027	                format!("{}", ival)
1028	            } else {
1029	                let fval = state.to_number(idx).unwrap_or(0.0);
1030	                // C: LUA_NUMBER_FMT = "%.14g" — significant-digit format
1031	                // TODO(port): implement proper %.14g (choose between %e and %f based on magnitude)
