1035	                Ok(n) => overall_ok = overall_ok && n == s.len(),
1036	                Err(_) => overall_ok = false,
1037	            }
1038	        } else {
1039	            // C: const char *s = luaL_checklstring(L, arg, &l);
1040	            // C: status = status && (fwrite(s, sizeof(char), l, f) == l);
1041	            let s: Vec<u8> = state.check_arg_string(idx)?;
1042	            match file.write_bytes(&s) {
1043	                Ok(n) => overall_ok = overall_ok && n == s.len(),
1044	                Err(_) => overall_ok = false,
1045	            }
1046	        }
1047	    }
