1062	/// `io.write(...)`. C: `io_write`.
1063	///
1064	/// Writes all arguments to the current default output file (`IO_OUTPUT`). When
1065	/// a file was set via `io.output(filename)`, writes go to that file; otherwise
1066	/// they go to stdout via `state.write_output()`.
1067	///
1068	/// The borrow split (needing both `&mut LuaState` and `&mut dyn LuaFileHandle`)
1069	/// is resolved by collecting all formatted strings first and then writing them
1070	/// to the file handle obtained from the `LSTREAM_REGISTRY`.
1071	pub fn io_write(state: &mut LuaState) -> Result<usize, LuaError> {
1072	    // C: g_write(L, getiofile(L, IO_OUTPUT), 1)
1073	    // Step 1: collect all formatted byte strings before touching the file handle.
1074	    let n = state.top();
1075	    let mut chunks: Vec<Vec<u8>> = Vec::with_capacity(n as usize);
1076	    for i in 1..=(n as i32) {
1077	        if state.type_at(i) == LuaType::Number {
1078	            let s = if state.is_integer(i) {
1079	                let ival = state.to_integer(i).unwrap_or(0);
1080	                // C: LUA_INTEGER_FMT = "%lld"
1081	                format!("{}", ival).into_bytes()
1082	            } else {
1083	                let fval = state.to_number(i).unwrap_or(0.0);
1084	                // TODO(port): proper %.14g (significant-digit) formatting.
1085	                format!("{:.14e}", fval).into_bytes()
1086	            };
1087	            chunks.push(s);
1088	        } else {
1089	            let bytes: Vec<u8> = state.check_arg_string(i)?;
1090	            chunks.push(bytes);
1091	        }
1092	    }
1093	
1094	    // Step 2: get the current output file handle from LSTREAM_REGISTRY if possible.
1095	    // Push the IO_OUTPUT userdata to the stack to read its identity, then pop it.
1096	    // The metatable check also verifies this is a live (not collected) file handle.
1097	    let ud_id: Option<usize> = {
1098	        state.registry_get(IO_OUTPUT_KEY)?;
1099	        let id = state.test_arg_userdata(-1, LUA_FILE_HANDLE)
1100	            .map(|ud| ud.identity());
1101	        state.pop_n(1);
1102	        id
1103	    };
1104	
1105	    if let Some(id) = ud_id {
1106	        if let Some(rc) = lookup_lstream(id) {
1107	            let mut p = rc.borrow_mut();
1108	            if let Some(fh) = p.file.as_mut() {
1109	                for chunk in &chunks {
1110	                    fh.write_bytes(chunk).map_err(|e| {
1111	                        LuaError::runtime(format_args!("io.write: {}", e))
1112	                    })?;
1113	                }
1114	                drop(p);
1115	                state.registry_get(IO_OUTPUT_KEY)?;
1116	                return Ok(1);
1117	            }
1118	        }
1119	    }
1120	
1121	    // Fallback: IO_OUTPUT is not a live file handle; write to the VM stdout sink.
1122	    for chunk in &chunks {
1123	        state.write_output(chunk)?;
1124	    }
1125	    state.registry_get(IO_OUTPUT_KEY)?;
1126	    Ok(1)
1127	}
